class Stack {
  constructor() {
    this.items = [];
  }
  
  push(element) {
    this.items.push(element);
    console.log("Pushed: " + element);
  }
  
  pop() {
    if (this.isEmpty()) {
      return "Stack is empty";
    }
    let removed = this.items.pop();
    console.log("Popped: " + removed);
    return removed;
  }
  
  isEmpty() {
    return this.items.length === 0;
  }
  
  peek() {
    return this.items[this.items.length - 1];
  }
}

// Run demonstration
let stack = new Stack();
stack.push(10);
stack.push(20);
stack.push(30);
stack.pop();
